SELECT AVG(t.amount_received) AS average_received_amount
FROM transactions t
WHERE t.status = 'completed' AND t.payment_gateway IN ('PayPal', 'Stripe');

SELECT SUM(amount_sent) AS total_amount_sent
FROM transactions
WHERE status = 'completed' AND type = 'payment';

SELECT AVG(amount_received) AS avg_amount_received
FROM transactions
WHERE status = 'Completed' AND payment_gateway = 'Stripe';

SELECT COUNT(transaction_id) AS transaction_count
FROM transactions
WHERE status = 'completed' AND payment_gateway = 'Stripe';
